class TextEditor {
    private StringBuilder text;
    private int cursor;

    public TextEditor() {
        text = new StringBuilder();
        cursor = 0;
    }

    public void addText(String text) {
        text.append(text);
        cursor += text.length();
    }

    public int deleteText(int k) {
        if (cursor == 0) {
            return 0;
        }
        int deleted = Math.min(k, cursor);
        text.delete(cursor - deleted, cursor);
        cursor -= deleted;
        return deleted;
    }

    public String cursorLeft(int k) {
        if (cursor == 0) {
            return "";
        }
        int newCursor = Math.max(0, cursor - k);
        return text.substring(newCursor, Math.min(newCursor + 10, cursor));
    }

    public String cursorRight(int k) {
        if (cursor >= text.length()) {
            return "";
        }
        int newCursor = Math.min(cursor + k, text.length());
        return text.substring(Math.max(0, newCursor - 10), newCursor);
    }
}
